// src/pages/LoginPage.js

import React, { useState } from "react";
import { auth } from "../firebaseConfig"; // Ensure this import is correct
import { signInWithEmailAndPassword } from "firebase/auth"; // Import the sign-in function
import { useAuth } from "../context/AuthContext"; // Import the Auth context
import { useNavigate } from "react-router-dom"; // Import useNavigate for navigation

const LoginPage = () => {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const { currentUser } = useAuth(); // Get the current user from context
  const navigate = useNavigate(); // Use the navigate function for navigation

  const handleLogin = async (e) => {
    e.preventDefault();
    setError(""); // Clear previous errors
    console.log("LoginPage rendered");


    try {
      await signInWithEmailAndPassword(auth, email, password); // Sign in with Firebase auth
      navigate("/landing"); // Redirect to the landing page after successful login
    } catch (error) {
      console.error("Error logging in:", error); // Log the error for debugging
      setError(error.message); // Show Firebase error message
    }
  };

  return (
    <div style={{ maxWidth: "400px", margin: "0 auto", textAlign: "center", padding: "50px" }}>
      <h2>Login</h2>
      {error && <p style={{ color: "red" }}>{error}</p>} {/* Display error message */}
      {currentUser ? (
        <p>Welcome back, {currentUser.email}!</p>
      ) : (
        <form onSubmit={handleLogin}>
          <div style={{ marginBottom: "1rem" }}>
            <label>Email:</label>
            <input
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              required
              style={{ width: "100%", padding: "8px" }}
            />
          </div>
          <div style={{ marginBottom: "1rem" }}>
            <label>Password:</label>
            <input
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              required
              style={{ width: "100%", padding: "8px" }}
            />
          </div>
          <button type="submit" style={{ padding: "10px 20px" }}>
            Log In
          </button>
        </form>

      )}
    </div>
  );
};

export default LoginPage;
